sql:
SELECT p.name
FROM patients p
JOIN (
    SELECT patient_id
    FROM vital_signs
    WHERE blood_pressure_systolic = (
        SELECT MAX(blood_pressure_systolic) FROM vital_signs
    )
) vs ON p.patient_id = vs.patient_id;

SELECT name
FROM patients
WHERE patient_id = 1;

SELECT p.name
FROM patients p
JOIN lab_results lr ON p.patient_id = lr.patient_id
WHERE lr.blast_cell_count = (
    SELECT MAX(blast_cell_count) FROM lab_results
);
